INSERT INTO activities (category_id, title, description, difficulty, estimated_time, xp, coins, benefits, instructions, tips) VALUES
('a0000000-0000-0000-0000-000000000001', 'Free Recall', 'After reading, close the book and write down everything you remember.', 'beginner', 10, 15, 5, '["Strengthens memory retrieval", "Improves active recall"]', 'Read a short article or chapter, then write down all key points from memory.', 'Do this immediately after reading for maximum effect.'),
('a0000000-0000-0000-0000-000000000001', 'Memory Palace', 'Use a familiar location to memorize a list of items.', 'intermediate', 15, 20, 8, '["Enhances spatial memory", "Builds mnemonic skills"]', 'Visualize a familiar route and place items along it mentally.', NULL),
('a0000000-0000-0000-0000-000000000001', 'Name Recall Challenge', 'Meet someone new and make a deliberate effort to remember their name.', 'beginner', 5, 10, 3, '["Improves social memory", "Builds connection habit"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Story Method', 'Create a story that links random items together to remember them.', 'beginner', 10, 15, 5, '["Strengthens associative memory", "Boosts creativity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Reverse Timeline', 'Recall your day in reverse chronological order.', 'intermediate', 10, 18, 6, '["Sharpens episodic memory", "Increases mindfulness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Number Mnemonics', 'Convert numbers into words or images to remember them.', 'intermediate', 12, 18, 6, '["Improves number recall", "Teaches mnemonic systems"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Photo Memory Drill', 'Study an image for 30 seconds, then describe it in detail from memory.', 'advanced', 10, 22, 8, '["Enhances visual memory", "Increases attention to detail"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Lyrics Recall', 'Listen to a song and write down the lyrics from memory.', 'beginner', 10, 12, 4, '["Trains auditory memory", "Fun and engaging"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Grocery List Challenge', 'Go shopping without a written list — use only your memory.', 'beginner', 15, 12, 5, '["Real-world memory training", "Practical skill building"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Chunking Practice', 'Break long strings of information into chunks.', 'beginner', 8, 10, 3, '["Improves working memory", "Enhances information processing"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Flashcard Review', 'Review flashcards for a topic you are learning.', 'beginner', 10, 12, 4, '["Strengthens long-term memory", "Uses spaced repetition"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Telephone Number Recall', 'Memorize a phone number by repeating it in chunks throughout the day.', 'beginner', 5, 8, 3, '["Everyday memory practice", "Easy to integrate"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Visual Association', 'Connect new information to vivid mental images.', 'intermediate', 12, 18, 6, '["Deepens encoding", "Makes information stick"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Memory Competition', 'Challenge a friend to a memory game — who can remember more items?', 'intermediate', 15, 20, 10, '["Social motivation", "Pressure training"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Method of Loci', 'Place items you want to remember along a familiar journey.', 'advanced', 15, 25, 10, '["Ancient memory technique", "Highly effective"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Card Recall', 'Shuffle a deck of cards and try to recall the order after studying it.', 'intermediate', 10, 20, 8, '["Visual memory", "Pattern recognition"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Face-Name Matching', 'Look at photos of strangers and match faces to names after 5 minutes.', 'intermediate', 10, 18, 6, '["Social memory", "Real-world skill"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Shopping Receipt Recall', 'Study a receipt for 2 minutes, then list every item from memory.', 'beginner', 5, 12, 4, '["Working memory", "Attention to detail"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Memory Maze', 'Study a simple maze for 1 minute, then draw it from memory.', 'advanced', 8, 22, 8, '["Spatial memory", "Visual reconstruction"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Color-Number Association', 'Memorize a list of color-number pairs, then recall them under time pressure.', 'intermediate', 8, 16, 6, '["Associative memory", "Speed recall"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Daily Details Log', 'At the end of the day, write down 10 specific details you noticed.', 'beginner', 8, 10, 3, '["Observational memory", "Mindfulness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Word List Battle', 'Study 20 random words, then recall as many as possible in 2 minutes.', 'beginner', 5, 12, 4, '["Short-term memory", "Competitive fun"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', 'Music Interval Memory', 'Listen to two musical notes and identify the interval between them.', 'advanced', 10, 25, 10, '["Auditory memory", "Ear training"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000001', '3-Item Carry', 'Keep 3 random items in your working memory all day without writing them down.', 'intermediate', 5, 15, 5, '["Working memory stamina", "Mental discipline"]', NULL, NULL);
INSERT INTO activities (category_id, title, description, difficulty, estimated_time, xp, coins, benefits, instructions, tips) VALUES
('a0000000-0000-0000-0000-000000000002', 'Pomodoro Session', 'Work for 25 minutes, rest for 5. Repeat 4 times.', 'beginner', 25, 20, 8, '["Builds focus endurance", "Prevents burnout"]', 'Set a timer for 25 minutes of uninterrupted work, then take a 5-minute break.', NULL),
('a0000000-0000-0000-0000-000000000002', 'Deep Work Block', 'Spend 60 minutes on a single task with zero distractions.', 'advanced', 60, 40, 15, '["Builds intense concentration", "Produces high-quality output"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Single-Tasking Exercise', 'Do one thing at a time for 30 minutes — no multitasking.', 'intermediate', 30, 25, 10, '["Breaks multitasking habit", "Improves quality of work"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Distraction Log', 'Every time you get distracted, write down what pulled your attention.', 'beginner', 15, 15, 5, '["Identifies distraction patterns", "Builds self-awareness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Mindful Breathing', 'Focus on your breath for 5 minutes. When your mind wanders, bring it back.', 'beginner', 5, 10, 3, '["Calms the mind", "Builds focus muscle"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Digital Detox Hour', 'Spend one hour with no screens — read, walk, or journal.', 'intermediate', 60, 30, 12, '["Reduces digital dependency", "Restores attention span"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Listening Drill', 'Listen to a podcast or talk and summarize key points afterward.', 'beginner', 15, 12, 5, '["Improves auditory focus", "Active listening practice"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'No-Interruption Meeting', 'In your next conversation, listen without interrupting.', 'beginner', 10, 10, 4, '["Builds patience", "Improves relationships"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Focus Timer Challenge', 'Gradually increase your focus session by 5 minutes each day.', 'intermediate', 30, 22, 8, '["Progressive overload for attention", "Measurable improvement"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Environmental Audit', 'Remove 3 distractions from your workspace.', 'beginner', 10, 10, 4, '["Optimizes workspace", "Reduces friction"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Reading Retention', 'Read a page slowly and summarize each paragraph in one sentence.', 'intermediate', 15, 18, 6, '["Deep reading practice", "Improves comprehension"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Meditation Session', 'Sit in silence and focus on your breath or a single point of attention.', 'beginner', 10, 15, 5, '["Reduces stress", "Builds concentration"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Flow State Prep', 'Set clear goals, remove distractions, and start your most important task.', 'intermediate', 20, 20, 8, '["Prepares mind for deep work", "Increases productivity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Attention Meditation', 'Focus on a single object (like a candle flame) for 10 minutes.', 'intermediate', 10, 18, 6, '["Sharpens visual focus", "Calms mental chatter"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Dual N-Back', 'Practice the dual n-back exercise for working memory and focus.', 'advanced', 15, 25, 10, '["Scientifically validated", "Improves fluid intelligence"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'One-Thing Challenge', 'Pick ONE task and do it for 45 minutes with zero context switching.', 'advanced', 45, 35, 15, '["Deep focus endurance", "Quality output"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Focus Bingo', 'Create a bingo card of distractions — mark each time you resist one.', 'beginner', 15, 12, 5, '["Gamifies focus", "Positive reinforcement"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Time Block Planning', 'Plan your entire day in 30-minute blocks — stick to the schedule.', 'intermediate', 15, 18, 6, '["Structured day", "Reduces decision fatigue"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Notification Fast', 'Turn off all non-essential notifications for 4 hours.', 'intermediate', 5, 20, 8, '["Reduces interruptions", "Restores attention"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Visual Fixation', 'Stare at a fixed point on the wall for 5 minutes without looking away.', 'beginner', 5, 10, 4, '["Concentration training", "Mental stillness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Counting Breaths', 'Count 100 breaths without losing track — start over if you do.', 'intermediate', 10, 15, 5, '["Sustained attention", "Mindfulness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Reading Without Subvocalizing', 'Read a page without silently saying the words in your head.', 'advanced', 10, 22, 8, '["Speed reading prep", "Quiets inner voice"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Monotask Meal', 'Eat a meal with no phone, TV, book, or conversation — just eating.', 'beginner', 15, 10, 4, '["Mindful eating", "Single-tasking practice"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000002', 'Concentration Game', 'Play a card matching game (memory-style) for 10 minutes.', 'beginner', 10, 12, 4, '["Visual focus", "Working memory"]', NULL, NULL);
INSERT INTO activities (category_id, title, description, difficulty, estimated_time, xp, coins, benefits, instructions, tips) VALUES
('a0000000-0000-0000-0000-000000000003', 'Decision Journal', 'Write a decision you made today, why you made it, and the expected outcome.', 'beginner', 10, 15, 5, '["Improves decision quality", "Builds self-awareness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'First Principles Analysis', 'Break a problem down to its fundamental truths and reason up from there.', 'advanced', 20, 30, 12, '["Teaches fundamental thinking", "Breaks assumptions"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Pros & Cons Grid', 'List pros and cons of a decision you are facing.', 'beginner', 10, 12, 4, '["Clarifies thinking", "Reduces decision fatigue"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Second-Order Thinking', 'For a decision, ask "and then what?" five times.', 'intermediate', 12, 20, 8, '["Long-term thinking", "Anticipates consequences"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Inversion Exercise', 'Instead of asking how to succeed, ask how to fail — then avoid those things.', 'intermediate', 10, 18, 6, '["Reveals blind spots", "Risk management"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Mental Model Review', 'Learn and apply one mental model (e.g. Occam''s Razor, Pareto Principle).', 'intermediate', 15, 20, 8, '["Expands thinking toolkit", "Better decisions"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Devil''s Advocate', 'Argue the opposite side of your own belief for 10 minutes.', 'intermediate', 10, 18, 6, '["Reduces bias", "Builds intellectual humility"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Premortem Analysis', 'Imagine your project failed completely — what went wrong?', 'advanced', 15, 25, 10, '["Identifies risks early", "Proactive problem solving"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Cognitive Bias Check', 'Identify 3 cognitive biases that might be affecting your current thinking.', 'advanced', 12, 22, 8, '["Reduces irrational thinking", "Self-correction skill"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Thought Experiment', 'Explore a "what if" scenario in detail.', 'beginner', 10, 12, 4, '["Expands imagination", "Creative problem solving"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Socratic Questioning', 'Challenge your own assumptions by asking "why" five times.', 'intermediate', 10, 18, 6, '["Deeper understanding", "Uncover root causes"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Probabilistic Thinking', 'Assign probabilities to different outcomes and update as you learn more.', 'advanced', 15, 25, 10, '["Better risk assessment", "Calibrated decision making"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Argument Mapping', 'Draw a visual map of an argument showing premises and conclusions.', 'advanced', 20, 28, 10, '["Clarifies complex reasoning", "Improves logic"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Post-Mortem Review', 'Analyze a recent failure or mistake and extract lessons.', 'intermediate', 15, 20, 8, '["Learning from failure", "Continuous improvement"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Lateral Thinking Puzzle', 'Solve a lateral thinking puzzle that requires creative connections.', 'intermediate', 10, 18, 6, '["Breaks rigid thinking", "Encourages creativity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Decision Matrix', 'Create a weighted decision matrix for a choice you are facing.', 'intermediate', 20, 22, 8, '["Structured decisions", "Quantitative thinking"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Occam''s Razor Exercise', 'Take a complex problem and find the simplest possible explanation.', 'beginner', 10, 15, 5, '["Simplifies complexity", "Critical thinking"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Word Association Chain', 'Start with one word and create a chain of associations — see where you end up.', 'beginner', 5, 8, 3, '["Divergent thinking", "Creativity warm-up"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Logical Fallacy Hunt', 'Find 3 logical fallacies in today''s news, ads, or conversations.', 'advanced', 10, 25, 10, '["Critical thinking", "Media literacy"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'System Thinking Map', 'Draw a system map showing how parts of a problem interact.', 'advanced', 20, 30, 12, '["Systems thinking", "Holistic view"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Hypothesis Testing', 'State a hypothesis, design a mini-experiment, and test it today.', 'advanced', 20, 28, 10, '["Scientific thinking", "Empirical mindset"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Chess Puzzle', 'Solve a chess puzzle (find the best move in a given position).', 'intermediate', 10, 20, 8, '["Strategic thinking", "Pattern recognition"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Sudoku', 'Complete a Sudoku puzzle (medium difficulty).', 'beginner', 15, 15, 5, '["Logical reasoning", "Concentration"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000003', 'Straw Man Self-Critique', 'Build the weakest version of your argument and then demolish it.', 'advanced', 12, 22, 8, '["Intellectual rigor", "Antifragile thinking"]', NULL, NULL);
INSERT INTO activities (category_id, title, description, difficulty, estimated_time, xp, coins, benefits, instructions, tips) VALUES
('a0000000-0000-0000-0000-000000000004', 'Read 15 Minutes', 'Read a book or long-form article for 15 minutes.', 'beginner', 15, 15, 5, '["Builds knowledge", "Improves focus"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Teach Someone Else', 'Explain a concept you learned today to someone else.', 'intermediate', 15, 25, 10, '["Deepens understanding", "Identifies gaps"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Feynman Technique', 'Explain a concept in simple terms as if teaching a child.', 'intermediate', 15, 22, 8, '["Reveals gaps in knowledge", "Simplifies complex ideas"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Active Recall Session', 'Close your notes and try to recall everything from memory.', 'beginner', 10, 15, 5, '["Strengthens neural pathways", "High retention"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Learn One New Word', 'Look up a new word, its meaning, and use it in a sentence today.', 'beginner', 5, 8, 3, '["Expands vocabulary", "Quick win"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Online Course Module', 'Complete one module of an online course.', 'intermediate', 30, 30, 12, '["Structured learning", "Skill building"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Summarize What You Learned', 'Write a 3-sentence summary of something new you learned today.', 'beginner', 5, 10, 3, '["Consolidates learning", "Builds writing habit"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Cross-Discipline Reading', 'Read about a topic completely outside your field.', 'beginner', 15, 15, 5, '["Widens perspective", "Encourages curiosity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Skill Practice Session', 'Dedicated practice of a skill you are developing.', 'intermediate', 30, 25, 10, '["Deliberate practice", "Accelerates mastery"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Read and Reflect', 'Read a passage and write a reflection on how it applies to your life.', 'beginner', 15, 15, 5, '["Connects learning to life", "Deep comprehension"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Flashcard Creation', 'Create 10 flashcards for a topic you are studying.', 'beginner', 10, 12, 4, '["Active learning", "Study tool creation"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Podcast Learning', 'Listen to an educational podcast and note 3 key takeaways.', 'beginner', 20, 15, 5, '["Learning on the go", "Auditory learning"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Spaced Repetition Review', 'Review material you learned 1, 3, and 7 days ago.', 'intermediate', 15, 22, 8, '["Long-term retention", "Efficient study"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Visual Note-Taking', 'Create a visual mind map of a topic instead of linear notes.', 'beginner', 15, 15, 5, '["Visual thinking", "Better connections"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Learning Journal Entry', 'Write in your learning journal: what you learned, how you learned it, and what is next.', 'beginner', 8, 10, 4, '["Metacognition", "Tracking progress"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Wikipedia Rabbit Hole', 'Start on one Wikipedia page and follow links to learn about 5 connected topics.', 'beginner', 15, 12, 4, '["Curiosity-driven learning", "Makes connections"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Skill Swap', 'Teach someone a skill you know and have them teach you one in return.', 'intermediate', 30, 30, 12, '["Reciprocal learning", "Social connection"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Documentary Deep Dive', 'Watch a documentary on a topic you know nothing about.', 'beginner', 45, 20, 8, '["Broadens horizons", "Passive learning"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Mistake Analysis', 'Review a recent mistake and identify the specific knowledge gap that caused it.', 'intermediate', 10, 18, 6, '["Targeted learning", "Growth mindset"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Dual Coding Practice', 'Learn a concept using both words AND visuals simultaneously.', 'intermediate', 15, 20, 8, '["Dual coding theory", "Stronger encoding"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Interleaved Practice', 'Study 3 different topics in rotation instead of one topic at a time.', 'advanced', 30, 28, 10, '["Better discrimination", "Transferable knowledge"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'How Things Work', 'Pick an everyday object and learn exactly how it works.', 'beginner', 10, 10, 4, '["Curiosity", "Practical knowledge"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Anki Session', 'Review your Anki (or other spaced repetition) deck for 10 minutes.', 'beginner', 10, 12, 4, '["Spaced repetition", "Long-term retention"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000004', 'Reading Sprint', 'Read as many pages as possible in 10 minutes, then summarize.', 'intermediate', 10, 15, 5, '["Speed reading practice", "Comprehension under pressure"]', NULL, NULL);
INSERT INTO activities (category_id, title, description, difficulty, estimated_time, xp, coins, benefits, instructions, tips) VALUES
