('a0000000-0000-0000-0000-000000000005', 'Posture Check', 'Maintain good posture throughout the day — set hourly reminders.', 'beginner', 5, 8, 3, '["Improves oxygen flow", "Reduces fatigue"]', NULL, NULL),
