('a0000000-0000-0000-0000-000000000005', 'Breathing Exercise', '5 minutes of box breathing (4-4-4-4 pattern).', 'beginner', 5, 8, 3, '["Reduces stress", "Calms nervous system"]', NULL, NULL),
