INSERT INTO activities (category_id, title, description, difficulty, estimated_time, xp, coins, benefits, instructions, tips) VALUES
('a0000000-0000-0000-0000-000000000006', 'Morning Pages', 'Write 3 pages of stream-of-consciousness thoughts first thing.', 'beginner', 15, 15, 5, '["Clears mental clutter", "Unlocks creativity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Brainstorm 10 Ideas', 'Generate 10 ideas for a problem you are facing — no judgment allowed.', 'beginner', 10, 15, 5, '["Divergent thinking", "Overcomes creative block"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Constraint Creation', 'Create something with an artificial constraint (e.g. only 50 words).', 'intermediate', 15, 20, 8, '["Forces creative solutions", "Breaks habits"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Idea Combination', 'Combine two unrelated concepts to create something new.', 'intermediate', 10, 18, 6, '["Innovative thinking", "Makes unexpected connections"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Creative Journaling', 'Write a short story, poem, or creative reflection.', 'beginner', 15, 15, 5, '["Self-expression", "Creativity practice"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Reverse Brainstorming', 'Brainstorm ways to make a problem worse, then reverse the ideas.', 'intermediate', 10, 18, 6, '["Unconventional solutions", "Fun approach"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Analogies Exercise', 'Find 3 analogies for a concept you are working on.', 'intermediate', 12, 18, 6, '["Connects domains", "Deepens understanding"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Doodle Session', 'Spend 10 minutes doodling without any goal.', 'beginner', 10, 10, 4, '["Relaxes the mind", "Sparks ideas"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'SCAMPER Exercise', 'Apply SCAMPER (Substitute, Combine, Adapt...) to an existing product.', 'advanced', 15, 25, 10, '["Structured creativity", "Innovation technique"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Random Word Association', 'Open a book to a random word and connect it to your current problem.', 'beginner', 8, 12, 4, '["Breaks thought patterns", "Sparks new ideas"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Creative Challenge', 'Complete a daily creative challenge (draw, write, compose, build).', 'intermediate', 20, 22, 8, '["Builds creative muscle", "Daily practice"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Mind Mapping', 'Create a mind map for a topic or problem.', 'beginner', 15, 15, 5, '["Visual thinking", "Makes connections"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'What If Scenario', 'Ask "what if" about a current situation and explore the possibilities.', 'beginner', 10, 12, 4, '["Expands thinking", "Imaginative exploration"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Creative Constraints', 'Solve a problem using only resources you already have.', 'intermediate', 15, 20, 8, '["Resourcefulness", "Practical creativity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Original Idea Challenge', 'Come up with one completely original idea today.', 'beginner', 10, 15, 5, '["Original thinking", "Innovation practice"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Six Hats Thinking', 'Analyze a problem from 6 perspectives: facts, emotions, risks, benefits, creativity, process.', 'advanced', 20, 30, 12, '["Multi-perspective thinking", "Structured creativity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Color Palette Creation', 'Create a 5-color palette inspired by a photo or mood.', 'beginner', 10, 10, 4, '["Visual creativity", "Design skills"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Metaphor Making', 'Describe your current challenge using a metaphor from a completely different domain.', 'intermediate', 8, 18, 6, '["Abstract thinking", "Fresh perspectives"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Musical Improv', 'Hum or whistle a melody you have never heard before — record it.', 'beginner', 5, 12, 4, '["Musical creativity", "Self-expression"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Interview Preparation', 'Prepare 10 creative questions to ask someone interesting.', 'beginner', 10, 12, 4, '["Curiosity practice", "Conversation skills"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Rebrand Exercise', 'Pick a famous brand and redesign its identity (name, logo, tagline).', 'intermediate', 20, 22, 8, '["Creative thinking", "Brand strategy"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Photo Challenge', 'Take 10 photos with a theme — find beauty in everyday objects.', 'beginner', 15, 12, 5, '["Visual creativity", "Mindfulness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Alternate Uses', 'Pick an object and list 20 alternate uses for it.', 'beginner', 6, 10, 4, '["Divergent thinking", "Creativity warm-up"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Poetry Exercise', 'Write a haiku (5-7-5) about your day.', 'beginner', 5, 10, 4, '["Creative constraint", "Self-expression"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000006', 'Prototype Sprint', 'Build a rough prototype of an idea using whatever materials you have.', 'intermediate', 25, 25, 10, '["Rapid prototyping", "Hands-on creativity"]', NULL, NULL);
INSERT INTO activities (category_id, title, description, difficulty, estimated_time, xp, coins, benefits, instructions, tips) VALUES
('a0000000-0000-0000-0000-000000000007', 'Gratitude List', 'Write down 3 things you are grateful for today.', 'beginner', 5, 10, 3, '["Increases happiness", "Shifts perspective"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Emotion Labeling', 'Throughout the day, name the emotions you feel.', 'beginner', 10, 12, 4, '["Emotional awareness", "Self-regulation"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Active Listening Practice', 'In your next conversation, listen to understand, not to reply.', 'intermediate', 15, 20, 8, '["Better relationships", "Deeper connections"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Empathy Exercise', 'Imagine someone else''s perspective in detail — what do they feel?', 'intermediate', 10, 18, 6, '["Builds empathy", "Reduces conflict"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Journal Prompt: Today''s Emotions', 'Write about the strongest emotion you felt today and why.', 'beginner', 10, 12, 4, '["Self-reflection", "Emotional processing"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Compliment Someone', 'Give a genuine compliment to someone today.', 'beginner', 2, 8, 3, '["Spreads positivity", "Strengthens bonds"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Pause and Respond', 'Before responding to a triggering situation, pause for 5 seconds.', 'intermediate', 5, 15, 6, '["Reactive to responsive", "Better outcomes"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Nonviolent Communication', 'Practice the NVC framework: observation, feeling, need, request.', 'advanced', 15, 25, 10, '["Conflict resolution", "Clear communication"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Social Connection', 'Reach out to a friend or family member you haven''t spoken to recently.', 'beginner', 10, 12, 5, '["Strengthens relationships", "Builds support network"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Body Scan', 'Notice physical sensations in your body — where do you feel tension?', 'beginner', 5, 10, 3, '["Mind-body connection", "Stress awareness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'React vs Respond Analysis', 'Reflect on a recent reaction — how could you have responded differently?', 'intermediate', 10, 18, 6, '["Pattern recognition", "Emotional growth"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Values Check-In', 'Did your actions today align with your core values?', 'intermediate', 8, 15, 5, '["Value-driven living", "Authenticity"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Forgiveness Practice', 'Write a letter of forgiveness (you don''t need to send it).', 'advanced', 15, 25, 10, '["Emotional release", "Reduces resentment"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Self-Compassion Break', 'When you make a mistake, speak to yourself as you would to a friend.', 'beginner', 5, 10, 4, '["Reduces self-criticism", "Builds resilience"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Mindful Conversation', 'Have a conversation where you are fully present — no phone, no distractions.', 'intermediate', 20, 20, 8, '["Deep connection", "Quality interaction"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', '3 Good Things', 'Share three good things that happened today with someone else.', 'beginner', 5, 10, 4, '["Positivity practice", "Social bonding"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Emotional Diary', 'Track your emotions hourly for one day — notice patterns.', 'intermediate', 10, 18, 6, '["Pattern recognition", "Self-awareness"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Active Constructive Responding', 'When someone shares good news, respond with enthusiastic and specific interest.', 'intermediate', 5, 15, 6, '["Relationship building", "Positive psychology"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Boundary Setting', 'Identify one boundary you need to set and communicate it clearly.', 'advanced', 10, 25, 10, '["Self-respect", "Healthy relationships"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Mirror Exercise', 'Look at yourself in the mirror and say something kind for 2 minutes.', 'advanced', 2, 20, 8, '["Self-compassion", "Vulnerability practice"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Active Empathy Challenge', 'For one hour, imagine everyone you interact with is fighting a difficult battle.', 'intermediate', 60, 25, 10, '["Compassion", "Patience"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Reappraisal Practice', 'Take a negative situation and find 3 positive reframes for it.', 'intermediate', 8, 18, 6, '["Emotional regulation", "Cognitive flexibility"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Non-Judgment Day', 'Go one day without judging anyone (including yourself).', 'advanced', 5, 30, 12, '["Acceptance", "Inner peace"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Love Letter Writing', 'Write a heartfelt letter to someone you appreciate.', 'beginner', 15, 15, 5, '["Gratitude", "Deep connection"]', NULL, NULL),
('a0000000-0000-0000-0000-000000000007', 'Trigger Mapping', 'Identify 3 emotional triggers and plan a healthy response for each.', 'advanced', 15, 28, 10, '["Emotional mastery", "Self-regulation"]', NULL, NULL);
